283: // ListRequest is a generic container for the parameters required to perform a list operation.
284: // It contains a generic type T intended for a list predicate.
285: // It also contains a QueryParams object containing pagination constraints.
286: type ListRequest[P any] struct {
287: 	Predicate   P
288: 	QueryParams QueryParams
289: }
290: 
291: // ListOption is a function which can configure a ListRequest.
292: type ListOption[T any] func(*ListRequest[T])
293: 
294: // ListWithQueryParamOptions takes a set of functional options for QueryParam and returns a ListOption
295: // which applies them in order on the provided ListRequest.
296: func ListWithQueryParamOptions[T any](opts ...QueryOption) ListOption[T] {
297: 	return func(r *ListRequest[T]) {
298: 		for _, opt := range opts {
299: 			opt(&r.QueryParams)
300: 		}
301: 	}
302: }
303: 
304: // PageParameter is any type which exposes limit and page token
305: // accessors used to identify pages.
306: type PageParameter interface {
307: 	GetLimit() int32
308: 	GetPageToken() string
309: }
310: 
311: // OffsetPageParameter is a type which exposes an additional offset
312: // accessor for legacy paging implementations (page token supersedes).
313: type OffsetPageParameter interface {
314: 	PageParameter
315: 	GetOffset() int32
316: }
317: 
318: // ListWithParameters constructs a new ListRequest using the page parameters
319: // exposed by the provided PageParameter implementation.
320: func ListWithParameters[T any](t T, p PageParameter) *ListRequest[T] {
321: 	opts := []QueryOption{
322: 		WithLimit(uint64(p.GetLimit())),
323: 		WithPageToken(p.GetPageToken()),
324: 	}
325: 
326: 	if po, ok := p.(OffsetPageParameter); ok {
327: 		opts = append(opts, WithOffset(uint64(po.GetOffset())))
328: 	}
329: 
330: 	return ListWithOptions[T](t, ListWithQueryParamOptions[T](opts...))
331: }
332: 
333: // ListWithOptions constructs a new ListRequest using the provided ListOption.
334: func ListWithOptions[T any](t T, opts ...ListOption[T]) *ListRequest[T] {
335: 	req := &ListRequest[T]{
336: 		Predicate: t,
337: 	}
338: 
339: 	for _, opt := range opts {
340: 		opt(req)
341: 	}
342: 
343: 	return req
344: }
