179: // documentsFromFile parses and validates a document from a single fs.File instance
180: func documentsFromFile(fi fs.File, opts SnapshotOption) ([]*ext.Document, error) {
181: 	validator, err := validation.NewFeaturesValidator(opts.validatorOption...)
182: 	if err != nil {
183: 		return nil, err
184: 	}
185: 
186: 	stat, err := fi.Stat()
187: 	if err != nil {
188: 		return nil, err
189: 	}
190: 
191: 	buf := &bytes.Buffer{}
192: 	reader := io.TeeReader(fi, buf)
193: 
194: 	var docs []*ext.Document
195: 	extn := filepath.Ext(stat.Name())
196: 
197: 	var decode func(any) error
198: 	switch extn {
199: 	case ".yaml", ".yml":
200: 		// Support YAML stream by looping until we reach an EOF.
201: 		decode = yaml.NewDecoder(buf).Decode
202: 	case "", ".json":
