802: func paginate[T any](params storage.QueryParams, less func(i, j int) bool, items ...T) (storage.ResultSet[T], error) {
803: 	if len(items) == 0 {
804: 		return storage.ResultSet[T]{}, nil
805: 	}
806: 
807: 	set := storage.ResultSet[T]{
808: 		Results: items,
809: 	}
810: 
811: 	// sort by created_at and specified order
812: 	sort.Slice(set.Results, func(i, j int) bool {
813: 		if params.Order != storage.OrderAsc {
814: 			i, j = j, i
815: 		}
816: 
817: 		return less(i, j)
818: 	})
819: 
820: 	// parse page token as an offset integer
821: 	var offset int
822: 	v, err := strconv.ParseInt(params.PageToken, 10, 64)
823: 	if params.PageToken != "" && err != nil {
824: 		return storage.ResultSet[T]{}, errs.ErrInvalidf("pageToken is not valid: %q", params.PageToken)
825: 	}
826: 
827: 	offset = int(v)
828: 
829: 	if offset >= len(set.Results) {
830: 		return storage.ResultSet[T]{}, errs.ErrInvalidf("invalid offset: %d", offset)
831: 	}
832: 
833: 	// 0 means no limit on page size (all items from offset)
834: 	if params.Limit == 0 {
835: 		set.Results = set.Results[offset:]
836: 		return set, nil
837: 	}
838: 
839: 	// ensure end of page does not exceed entire set
840: 	end := offset + int(params.Limit)
841: 	if end > len(set.Results) {
842: 		end = len(set.Results)
843: 	} else if end < len(set.Results) {
844: 		// set next page token given there are more entries
845: 		set.NextPageToken = fmt.Sprintf("%d", end)
846: 	}
847: 
848: 	// reduce results set to requested page
849: 	set.Results = set.Results[offset:end]
850: 
851: 	return set, nil
